     1→// Copyright (c) 2014 Baidu.com, Inc. All rights reserved.
     2→// Use of this source code is governed by a BSD-style license that can be
     3→// found in the LICENSE file.
     4→//
     5→// Author: qinzuoyan01@baidu.com (Qin Zuoyan)
     6→
     7→#include <sofa/pbrpc/rpc_server_impl.h>
     8→#include <sofa/pbrpc/rpc_controller_impl.h>
     9→#include <sofa/pbrpc/tran_buf_pool.h>
    10→#include <sofa/pbrpc/flow_controller.h>
    11→#include <sofa/pbrpc/builtin_service_impl.h>
    12→#include <sofa/pbrpc/closure.h>
    13→#include <sofa/pbrpc/ptime.h>
    14→#include <sofa/pbrpc/compressed_stream.h>
    15→
    16→namespace sofa {
    17→namespace pbrpc {
    18→
    19→RpcServerImpl::RpcServerImpl(const RpcServerOptions& options,
    20→        RpcServer::EventHandler* handler)
    21→    : _options(options)
    22→    , _event_handler(handler)
    23→    , _is_running(false)
    24→    , _start_time(ptime_now())
    25→    , _ticks_per_second(time_duration_seconds(1).ticks())
    26→    , _last_maintain_ticks(0)
    27→    , _last_restart_listen_ticks(0)
    28→    , _last_switch_stat_slot_ticks(0)
    29→    , _last_print_connection_ticks(0)
    30→    , _live_stream_count(0)
    31→{
    32→    _service_pool.reset(new ServicePool(this));
    33→
    34→    _slice_count = std::max(1, 1000 / MAINTAIN_INTERVAL_IN_MS);
    35→    _slice_quota_in = _options.max_throughput_in == -1 ?
    36→        -1 : std::max(0L, _options.max_throughput_in * 1024L * 1024L) / _slice_count;
    37→    _slice_quota_out = _options.max_throughput_out == -1 ?
    38→        -1 : std::max(0L, _options.max_throughput_out * 1024L * 1024L) / _slice_count;
    39→    _max_pending_buffer_size =
    40→        std::max(0L, _options.max_pending_buffer_size * 1024L * 1024L);
    41→    _keep_alive_ticks = _options.keep_alive_time == -1 ?
    42→        -1 : std::max(1, _options.keep_alive_time) * _ticks_per_second;
    43→    _restart_listen_interval_ticks = _ticks_per_second * 3;
    44→    _switch_stat_slot_interval_ticks = _ticks_per_second * STAT_SLOT_SECONDS;
    45→    _print_connection_interval_ticks = _ticks_per_second * 60;
    46→
    47→#if defined( LOG )
    48→    LOG(INFO) << "RpcServerImpl(): quota_in="
    49→              << (_slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L))
    50→              << "MB/s, quota_out="
    51→              << (_slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L))
    52→              << "MB/s, max_pending_buffer_size="
    53→              << (_max_pending_buffer_size / (1024L * 1024L))
    54→              << "MB, keep_alive_time="
    55→              << (_keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second)
    56→              << "seconds";
    57→#else
    58→    SLOG(INFO, "RpcServerImpl(): quota_in=%lldMB/s, quota_out=%lldMB/s"
    59→            ", max_pending_buffer_size=%lldMB, keep_alive_time=%lldseconds",
    60→            _slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L),
    61→            _slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L),
    62→            _max_pending_buffer_size / (1024L * 1024L),
    63→            _keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second);
    64→#endif
    65→}
    66→
    67→RpcServerImpl::~RpcServerImpl()
    68→{
    69→    SOFA_PBRPC_FUNCTION_TRACE;
    70→    Stop();
    71→    _service_pool.reset();
    72→    if (_event_handler) delete _event_handler;
    73→}
    74→
    75→bool RpcServerImpl::Start(const std::string& server_address)
    76→{
    77→    ScopedLocker<MutexLock> _(_start_stop_lock);
    78→    if (_is_running) return true;
    79→
    80→    _flow_controller.reset(new FlowController(
    81→                _slice_quota_in == -1, _slice_quota_in,
    82→                _slice_quota_out == -1, _slice_quota_out));
    83→
    84→    _maintain_thread_group.reset(new ThreadGroupImpl(
    85→                1, "sofa_pbrpc_server_maintain_thread_group"));
    86→    if (!_maintain_thread_group->start())
    87→    {
    88→#if defined( LOG )
    89→        LOG(ERROR) << "Start(): start maintain thread group failed";
    90→#else
    91→        SLOG(ERROR, "Start(): start maintain thread group failed");
    92→#endif
    93→        _maintain_thread_group.reset();
    94→        _flow_controller.reset();
    95→    }
    96→
    97→    _work_thread_group.reset(new ThreadGroupImpl(
    98→                _options.work_thread_num, "sofa_pbrpc_server_work_thread_group"));
    99→    _work_thread_group->set_init_func(_options.work_thread_init_func);
   100→    _work_thread_group->set_dest_func(_options.work_thread_dest_func);
   101→    if (!_work_thread_group->start())
   102→    {
   103→#if defined( LOG )
   104→        LOG(ERROR) << "Start(): start work thread group failed";
   105→#else
   106→        SLOG(ERROR, "Start(): start work thread group failed");
   107→#endif
   108→        _work_thread_group.reset();
   109→        _maintain_thread_group.reset();
   110→        _flow_controller.reset();
   111→        return false;
   112→    }
   113→
   114→    _server_address = server_address;
   115→    if (!ResolveAddress(_work_thread_group->io_service(), _server_address, &_listen_endpoint))
   116→    {
   117→#if defined( LOG )
   118→        LOG(ERROR) << "Start(): resolve server address failed: " << _server_address;
   119→#else
   120→        SLOG(ERROR, "Start(): resolve server address failed: %s", _server_address.c_str());
   121→#endif
   122→        _work_thread_group.reset();
   123→        _maintain_thread_group.reset();
   124→        _flow_controller.reset();
   125→        return false;
   126→    }
   127→
   128→    _listener.reset(new RpcListener(_work_thread_group->io_service(), _listen_endpoint));
   129→    _listener->set_create_callback(boost::bind(
   130→                &RpcServerImpl::OnCreated, shared_from_this(), _1));
   131→    _listener->set_accept_callback(boost::bind(
   132→                &RpcServerImpl::OnAccepted, shared_from_this(), _1));
   133→    _listener->set_accept_fail_callback(boost::bind(
   134→                &RpcServerImpl::OnAcceptFailed, shared_from_this(), _1, _2));
   135→    if (!_listener->start_listen())
   136→    {
   137→#if defined( LOG )
   138→        LOG(ERROR) << "Start(): listen failed: " << _server_address;
   139→#else
   140→        SLOG(ERROR, "Start(): listen failed: %s", _server_address.c_str());
   141→#endif
   142→        _listener.reset();
   143→        _work_thread_group.reset();
   144→        _maintain_thread_group.reset();
   145→        _flow_controller.reset();
   146→        return false;
   147→    }
   148→#if defined( LOG )
   149→    LOG(INFO) << "Start(): listen succeed: " << _server_address
   150→              << " [" << RpcEndpointToString(_listen_endpoint) << "]";
   151→#else
   152→    SLOG(INFO, "Start(): listen succeed: %s [%s]",
   153→            _server_address.c_str(), RpcEndpointToString(_listen_endpoint).c_str());
   154→#endif
   155→
   156→    _timer_worker.reset(new TimerWorker(_maintain_thread_group->io_service()));
   157→    _timer_worker->set_time_duration(time_duration_milliseconds(MAINTAIN_INTERVAL_IN_MS));
   158→    _timer_worker->set_work_routine(boost::bind(
   159→                &RpcServerImpl::TimerMaintain, shared_from_this(), _1));
   160→    _timer_worker->start();
   161→
   162→    if (!_options.disable_builtin_services) {
   163→        _service_pool->RegisterService(new sofa::pbrpc::builtin::BuiltinServiceImpl(
   164→                    shared_from_this(), _service_pool, _options.disable_list_service));
   165→    }
   166→
   167→    _is_running = true;
   168→#if defined( LOG )
   169→    LOG(INFO) << "Start(): rpc server started";
   170→#else
   171→    SLOG(INFO, "Start(): rpc server started");
   172→#endif
   173→    return true;
   174→}
   175→
   176→void RpcServerImpl::Stop()
   177→{
   178→    ScopedLocker<MutexLock> _(_start_stop_lock);
   179→    if (!_is_running) return;
   180→    _is_running = false;
   181→
   182→    _timer_worker->stop();
   183→    _listener->close();
   184→    StopStreams();
   185→    _work_thread_group->stop();
   186→
   187→    _timer_worker.reset();
   188→    _listener.reset();
   189→    ClearStreams();
   190→    _maintain_thread_group->stop();
   191→
   192→    _work_thread_group.reset();
   193→    _maintain_thread_group.reset();
   194→    _flow_controller.reset();
   195→
   196→#if defined( LOG )
   197→    LOG(INFO) << "Stop(): rpc server stopped";
   198→#else
   199→    SLOG(INFO, "Stop(): rpc server stopped");
   200→#endif
   201→}
   202→
   203→PTime RpcServerImpl::GetStartTime()
   204→{
   205→    return _start_time;
   206→}
   207→
   208→RpcServerOptions RpcServerImpl::GetOptions()
   209→{
   210→    return _options;
   211→}
   212→
   213→void RpcServerImpl::ResetOptions(const RpcServerOptions& options)
   214→{
   215→    int64 old_slice_quota_in = _slice_quota_in;
   216→    int64 old_slice_quota_out = _slice_quota_out;
   217→    int64 old_max_pending_buffer_size = _max_pending_buffer_size;
   218→    int64 old_keep_alive_ticks = _keep_alive_ticks;
   219→
   220→    _options.max_throughput_in = options.max_throughput_in;
   221→    _options.max_throughput_out = options.max_throughput_out;
   222→    _options.max_pending_buffer_size = options.max_pending_buffer_size;
   223→    _options.keep_alive_time = options.keep_alive_time;
   224→
   225→    _slice_quota_in = _options.max_throughput_in == -1 ?
   226→        -1 : std::max(0L, _options.max_throughput_in * 1024L * 1024L) / _slice_count;
   227→    _slice_quota_out = _options.max_throughput_out == -1 ?
   228→        -1 : std::max(0L, _options.max_throughput_out * 1024L * 1024L) / _slice_count;
   229→    _max_pending_buffer_size = 
   230→        std::max(0L, _options.max_pending_buffer_size * 1024L * 1024L);
   231→    _keep_alive_ticks = _options.keep_alive_time == -1 ?
   232→        -1 : std::max(1, _options.keep_alive_time) * _ticks_per_second;
   233→
   234→    if (_max_pending_buffer_size != old_max_pending_buffer_size)
   235→    {
   236→        ScopedLocker<FastLock> _(_stream_list_lock);
   237→        for (StreamList::iterator it = _stream_list.begin(); it != _stream_list.end(); ++it)
   238→        {
   239→            (*it)->set_max_pending_buffer_size(_max_pending_buffer_size);
   240→        }
   241→    }
   242→
   243→    if (_slice_quota_in != old_slice_quota_in)
   244→    {
   245→        _flow_controller->reset_read_quota(_slice_quota_in == -1, _slice_quota_in);
   246→    }
   247→
   248→    if (_slice_quota_out != old_slice_quota_out)
   249→    {
   250→        _flow_controller->reset_write_quota(_slice_quota_out == -1, _slice_quota_out);
   251→    }
   252→
   253→#if defined( LOG )
   254→    LOG(INFO) << "ResetOptions(): quota_in="
   255→              << (_slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L))
   256→              << "MB/s(old "
   257→              << (old_slice_quota_in == -1 ? -1 : old_slice_quota_in * _slice_count / (1024L * 1024L))
   258→              << "MB/s), quota_out="
   259→              << (_slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L))
   260→              << "MB/s(old "
   261→              << (old_slice_quota_out == -1 ? -1 : old_slice_quota_out * _slice_count / (1024L * 1024L))
   262→              << "MB/s), max_pending_buffer_size="
   263→              << (_max_pending_buffer_size / (1024L * 1024L))
   264→              << "MB(old "
   265→              << (old_max_pending_buffer_size / (1024L * 1024L))
   266→              << "MB), keep_alive_time="
   267→              << (_keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second)
   268→              << "seconds(old "
   269→              << (old_keep_alive_ticks == -1 ? -1 : old_keep_alive_ticks / _ticks_per_second)
   270→              << "seconds)";
   271→#else
   272→    SLOG(INFO, "ResetOptions(): quota_in=%lldMB/s(old %lldMB/s)"
   273→            ", quota_out=%lldMB/s(old %lldMB/s)"
   274→            ", max_pending_buffer_size=%lldMB(old %lldMB)"
   275→            ", keep_alive_time=%lldseconds(old %lldseconds)",
   276→            _slice_quota_in == -1 ? -1 : _slice_quota_in * _slice_count / (1024L * 1024L),
   277→            old_slice_quota_in == -1 ? -1 : old_slice_quota_in * _slice_count / (1024L * 1024L),
   278→            _slice_quota_out == -1 ? -1 : _slice_quota_out * _slice_count / (1024L * 1024L),
   279→            old_slice_quota_out == -1 ? -1 : old_slice_quota_out * _slice_count / (1024L * 1024L),
   280→            _max_pending_buffer_size / (1024L * 1024L),
   281→            old_max_pending_buffer_size / (1024L * 1024L),
   282→            _keep_alive_ticks == -1 ? -1 : _keep_alive_ticks / _ticks_per_second,
   283→            old_keep_alive_ticks == -1 ? -1 : old_keep_alive_ticks / _ticks_per_second);
   284→#endif
   285→}
   286→
   287→bool RpcServerImpl::RegisterService(google::protobuf::Service* service, bool take_ownership)
   288→{
   289→    return _service_pool->RegisterService(service, take_ownership);
   290→}
   291→
   292→int RpcServerImpl::ServiceCount()
   293→{
   294→    return _service_pool->ServiceCount();
   295→}
   296→
   297→int RpcServerImpl::ConnectionCount()
   298→{
   299→    ScopedLocker<FastLock> _(_stream_list_lock);
   300→    return _stream_list.size();
   301→}
   302→
   303→void RpcServerImpl::GetPendingStat(int64* pending_message_count,
   304→        int64* pending_buffer_size, int64* pending_data_size)
   305→{
   306→    ScopedLocker<FastLock> _(_stream_list_lock);
   307→    int64 message_count = 0;
   308→    int64 buffer_size = 0;
   309→    int64 data_size = 0;
   310→    for (StreamList::iterator it = _stream_list.begin();
   311→            it != _stream_list.end(); ++it)
   312→    {
   313→        message_count += (*it)->pending_message_count();
   314→        buffer_size += (*it)->pending_buffer_size();
   315→        data_size += (*it)->pending_data_size();
   316→    }
   317→    *pending_message_count = message_count;
   318→    *pending_buffer_size = buffer_size;
   319→    *pending_data_size = data_size;
   320→}
   321→
   322→bool RpcServerImpl::IsListening()
   323→{
   324→    ScopedLocker<MutexLock> _(_start_stop_lock);
   325→    return _is_running && !_listener->is_closed();
   326→}
   327→
   328→bool RpcServerImpl::RestartListen()
   329→{
   330→    ScopedLocker<MutexLock> _(_start_stop_lock);
   331→    if (!_is_running)
   332→    {
   333→#if defined( LOG )
   334→        LOG(ERROR) << "RestartListen(): server not in running";
   335→#else
   336→        SLOG(ERROR, "RestartListen(): server not in running");
   337→#endif
   338→        return false;
   339→    }
   340→
   341→    // close listener first
   342→    _listener->close();
   343→
   344→    // reset and restart listener
   345→    _listener.reset(new RpcListener(_work_thread_group->io_service(), _listen_endpoint));
   346→    _listener->set_create_callback(boost::bind(
   347→                &RpcServerImpl::OnCreated, shared_from_this(), _1));
   348→    _listener->set_accept_callback(boost::bind(
   349→                &RpcServerImpl::OnAccepted, shared_from_this(), _1));
   350→    _listener->set_accept_fail_callback(boost::bind(
   351→                &RpcServerImpl::OnAcceptFailed, shared_from_this(), _1, _2));
   352→    if (!_listener->start_listen())
   353→    {
   354→#if defined( LOG )
   355→        LOG(ERROR) << "RestartListen(): listen failed: " << _server_address;
   356→#else
   357→        SLOG(ERROR, "RestartListen(): listen failed: %s", _server_address.c_str());
   358→#endif
   359→        return false;
   360→    }
   361→
   362→#if defined( LOG )
   363→    LOG(INFO) << "RestartListen(): restart listener succeed";
   364→#else
   365→    SLOG(INFO, "RestartListen(): restart listener succeed");
   366→#endif
   367→    return true;
   368→}
   369→
   370→void RpcServerImpl::OnCreated(const RpcServerStreamPtr& stream)
   371→{
   372→    stream->set_flow_controller(_flow_controller);
   373→    stream->set_received_request_callback(
   374→            boost::bind(&RpcServerImpl::OnReceived, shared_from_this(), _1, _2));
   375→}
   376→
   377→void RpcServerImpl::OnAccepted(const RpcServerStreamPtr& stream)
   378→{
   379→    if (!_is_running)
   380→    {
   381→        stream->close("server not running");
   382→        return;
   383→    }
   384→
   385→    stream->set_max_pending_buffer_size(_max_pending_buffer_size);
   386→    stream->reset_ticks((ptime_now() - _start_time).ticks(), true);
   387→
   388→    ScopedLocker<FastLock> _(_stream_list_lock);
   389→    _stream_list.push_back(stream);
   390→}
   391→
   392→void RpcServerImpl::OnAcceptFailed(RpcErrorCode error_code, const std::string& error_text)
   393→{
   394→    if (!_is_running)
   395→        return;
   396→
   397→    // callback
   398→    if (_event_handler)
   399→    {
   400→        _event_handler->NotifyAcceptFailed(error_code, error_text);
   401→    }
   402→}
   403→
   404→void RpcServerImpl::OnReceived(const RpcServerStreamWPtr& stream, const RpcRequestPtr& request)
   405→{
   406→    if (!_is_running)
   407→    {
   408→#if defined( LOG )
   409→        LOG(ERROR) << "OnReceived(): " << RpcEndpointToString(request->RemoteEndpoint())
   410→                   << ": server not in running, ignore";
   411→#else
   412→        SLOG(ERROR, "OnReceived(): %s: server not in running, ignore",
   413→                RpcEndpointToString(request->RemoteEndpoint()).c_str());
   414→#endif
   415→        return;
   416→    }
   417→
   418→    request->ProcessRequest(stream, _service_pool);
   419→}
   420→
   421→void RpcServerImpl::StopStreams()
   422→{
   423→    ScopedLocker<FastLock> _(_stream_list_lock);
   424→    for (StreamList::iterator it = _stream_list.begin();
   425→            it != _stream_list.end(); ++it)
   426→    {
   427→        (*it)->close("server stopped");
   428→    }
   429→}
   430→
   431→void RpcServerImpl::ClearStreams()
   432→{
   433→    ScopedLocker<FastLock> _(_stream_list_lock);
   434→    _stream_list.clear();
   435→}
   436→
   437→void RpcServerImpl::TimerMaintain(const PTime& now)
   438→{
   439→    SOFA_PBRPC_FUNCTION_TRACE;
   440→
   441→    int64 now_ticks = (now - _start_time).ticks();
   442→
   443→    // check listener, if closed, then try to restart it every interval.
   444→    if (_listener->is_closed()
   445→            && now_ticks - _last_restart_listen_ticks >= _restart_listen_interval_ticks)
   446→    {
   447→        _last_restart_listen_ticks = now_ticks;
   448→        RestartListen();
   449→    }
   450→
   451→    // check streams, if closed, then remove from list
   452→    std::list<RpcServerStreamPtr> live_streams;
   453→    std::list<RpcServerStreamPtr> closed_streams;
   454→    int live_count = 0;
   455→    {
   456→        ScopedLocker<FastLock> _(_stream_list_lock);
   457→        for (StreamList::iterator it = _stream_list.begin();
   458→                it != _stream_list.end(); )
   459→        {
   460→            const RpcServerStreamPtr& stream = *it;
   461→
   462→            if (_keep_alive_ticks != -1
   463→                    && now_ticks - stream->last_rw_ticks() >= _keep_alive_ticks)
   464→            {
   465→                stream->close("keep alive timeout");
   466→            }
   467→
   468→            if (stream->is_closed())
   469→            {
   470→                closed_streams.push_back(stream);
   471→                it = _stream_list.erase(it);
   472→            }
   473→            else
   474→            {
   475→                stream->reset_ticks(now_ticks, false);
   476→                live_streams.push_back(stream);
   477→                ++live_count;
   478→                ++it;
   479→            }
   480→        }
   481→    }
   482→    _live_stream_count = live_count;
   483→
   484→    // flow control
   485→    if (_slice_quota_in != -1)
   486→    {
   487→        // reset quota pool
   488→        _flow_controller->reset_read_quota(_slice_quota_in);
   489→
   490→        // collect streams need to trigger
   491→        std::vector<FlowControlItem> trigger_list;
   492→        for (std::list<RpcServerStreamPtr>::iterator it = live_streams.begin();
   493→                it != live_streams.end(); ++it)
   494→        {
   495→            int token = (*it)->read_quota_token();
   496→            if (token <= 0)
   497→            {
   498→                // only need trigger streams whose token <= 0
   499→                trigger_list.push_back(FlowControlItem(token, (*it).get()));
   500→            }
   501→        }
   502→
   503→        // sort by token: token closer to zero, earlier to trigger
   504→        std::sort(trigger_list.begin(), trigger_list.end());
   505→
   506→        // trigger in order
   507→        for (std::vector<FlowControlItem>::iterator t_it = trigger_list.begin();
   508→                t_it != trigger_list.end(); ++t_it)
   509→        {
   510→            t_it->stream->trigger_receive();
   511→        }
   512→    }
   513→    if (_slice_quota_out != -1)
   514→    {
   515→        // reset quota pool
   516→        _flow_controller->reset_write_quota(_slice_quota_out);
   517→
   518→        // collect streams need to trigger
   519→        std::vector<FlowControlItem> trigger_list;
   520→        for (std::list<RpcServerStreamPtr>::iterator it = live_streams.begin();
   521→                it != live_streams.end(); ++it)
   522→        {
   523→            int token = (*it)->write_quota_token();
   524→            if (token <= 0)
   525→            {
   526→                // only need trigger streams whose token <= 0
   527→                trigger_list.push_back(FlowControlItem(token, (*it).get()));
   528→            }
   529→        }
   530→
   531→        // sort by token: token closer to zero, earlier to trigger
   532→        std::sort(trigger_list.begin(), trigger_list.end());
   533→
   534→        // trigger in order
   535→        for (std::vector<FlowControlItem>::iterator t_it = trigger_list.begin();
   536→                t_it != trigger_list.end(); ++t_it)
   537→        {
   538→            t_it->stream->trigger_send();
   539→        }
   540→    }
   541→
   542→    if (now_ticks - _last_switch_stat_slot_ticks >= _switch_stat_slot_interval_ticks)
   543→    {
   544→        _last_switch_stat_slot_ticks = now_ticks;
   545→        _service_pool->NextSlot();
   546→    }
   547→
   548→    if (now_ticks - _last_print_connection_ticks >= _print_connection_interval_ticks)
   549→    {
   550→        _last_print_connection_ticks = now_ticks;
   551→#if defined( LOG )
   552→        LOG(INFO) << "TimerMaintain(): countof(RpcListener)="
   553→                  << SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcListener)
   554→                  << ", countof(RpcByteStream)=" << SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcByteStream)
   555→                  << ", live_stream_count=" << _live_stream_count;
   556→#else
   557→        SLOG(INFO, "TimerMaintain(): countof(RpcListener)=%ld"
   558→                ", countof(RpcByteStream)=%ld, live_stream_count=%d",
   559→                SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcListener),
   560→                SOFA_PBRPC_GET_RESOURCE_COUNTER(RpcByteStream),
   561→                _live_stream_count);
   562→#endif
   563→    }
   564→
   565→    _last_maintain_ticks = now_ticks;
   566→}
   567→
   568→} // namespace pbrpc
   569→} // namespace sofa
